var isPerfectSquare = function(num) {
    let lo = 1, hi = num;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        const sq = mid * mid;
        if (sq === num) return true;
        if (sq < num) lo = mid + 1; else hi = mid - 1;
    }
    return false;
};
